macro.implementation:
do {
  if ((usbp)->binder != NULL) {
    osalSysLockFromISR();
    usbBinderSOFI((usbp)->binder);
    osalSysUnlockFromISR();
  }
} while (false)

do {
  (usbp)->transmitting &= ~(uint16_t)((unsigned)1U << (unsigned)(ep));
  if ((usbp)->epc[ep]->in_cb != NULL) {
    (usbp)->epc[ep]->in_cb(usbp, ep);
  }
  osalSysLockFromISR();
  osalThreadResumeI(&(usbp)->epc[ep]->in_state->thread, MSG_OK);
  osalSysUnlockFromISR();
} while (false)

do {
  (usbp)->receiving &= ~(uint16_t)((unsigned)1U << (unsigned)(ep));
  if ((usbp)->epc[ep]->out_cb != NULL) {
    (usbp)->epc[ep]->out_cb(usbp, ep);
  }
  osalSysLockFromISR();
  osalThreadResumeI(&(usbp)->epc[ep]->out_state->thread,
                    usbGetReceiveTransactionSizeX(usbp, ep));
  osalSysUnlockFromISR();
} while (false)

types.verbatim:
typedef uint8_t usbep_t;
typedef driver_state_t usbstate_t;
struct hal_usb_service;
struct hal_usb_binder;

#define USB_SELECTED                       (HAL_DRV_STATE_ACTIVE + 1U)
#define USB_ACTIVE                         (HAL_DRV_STATE_ACTIVE + 2U)
#define USB_SUSPENDED                      (HAL_DRV_STATE_ACTIVE + 3U)

typedef enum {
  EP_STATUS_DISABLED = 0,
  EP_STATUS_STALLED  = 1,
  EP_STATUS_ACTIVE   = 2
} usbepstatus_t;

typedef enum {
  USB_EP0_STP_WAITING      = 0U,
  USB_EP0_IN_TX            = 1U,
  USB_EP0_IN_WAITING_TX0   = 2U,
  USB_EP0_IN_SENDING_STS   = 3U,
  USB_EP0_OUT_WAITING_STS  = 4U,
  USB_EP0_OUT_RX           = 5U,
  USB_EP0_ERROR            = 6U
} usbep0state_t;

typedef struct {
  size_t                    ud_size;
  const uint8_t            *ud_string;
} usb_descriptor_t;

typedef void (*usbcallback_t)(hal_usb_driver_c *usbp);
typedef void (*usbepcallback_t)(hal_usb_driver_c *usbp, usbep_t ep);

typedef struct {
  size_t                    txsize;
  size_t                    txcnt;
  size_t                    txlast;
  const uint8_t            *txbuf;
#if (USB_USE_SYNCHRONIZATION == TRUE) || defined(__DOXYGEN__)
  thread_reference_t        thread;
#endif
} USBInEndpointState;

typedef struct {
  size_t                    rxsize;
  size_t                    rxcnt;
  size_t                    rxpkts;
  uint8_t                  *rxbuf;
#if (USB_USE_SYNCHRONIZATION == TRUE) || defined(__DOXYGEN__)
  thread_reference_t        thread;
#endif
} USBOutEndpointState;

typedef struct {
  uint32_t                  ep_mode;
  usbepcallback_t           setup_cb;
  usbepcallback_t           in_cb;
  usbepcallback_t           out_cb;
  uint16_t                  in_maxsize;
  uint16_t                  out_maxsize;
  USBInEndpointState       *in_state;
  USBOutEndpointState      *out_state;
  unsigned                  ep_buffers;
  uint8_t                  *setup_buf;
} USBEndpointConfig;

/* Inclusion of LLD header.*/
#include "hal_usb_lld.h"

typedef struct usb_configurations usb_configurations_t;
struct usb_configurations {
  unsigned                  cfgsnum;
  hal_usb_config_t          cfgs[];
};

objinit.implementation:
self->binder = NULL;
self->info   = NULL;
self->arg    = NULL;
self->next   = NULL;
self->prev   = NULL;

method.implementation:
self = __usbsvc_objinit_impl(self, vmt);
self->info = infop;

return self;

unsigned base;
unsigned limit;

if ((self->info == NULL) || (self->info->if_count == 0U)) {
  return false;
}

base  = (unsigned)self->info->if_base;
limit = base + (unsigned)self->info->if_count;

return ((unsigned)ifn >= base) && ((unsigned)ifn < limit);

objinit.implementation:
self->usbp         = NULL;
self->services     = NULL;
self->service_last = NULL;
self->services_num = 0U;
self->arg          = NULL;

method.implementation:
hal_usb_service_c *servicep;

for (servicep = self->services; servicep != NULL; servicep = servicep->next) {
  usbServiceOnResetI(servicep);
}

hal_usb_service_c *servicep;

for (servicep = self->services; servicep != NULL; servicep = servicep->next) {
  usbServiceOnConfigureI(servicep);
}

hal_usb_service_c *servicep;

for (servicep = self->services; servicep != NULL; servicep = servicep->next) {
  usbServiceOnUnconfigureI(servicep);
}

hal_usb_service_c *servicep;

for (servicep = self->services; servicep != NULL; servicep = servicep->next) {
  usbServiceOnSuspendI(servicep);
}

hal_usb_service_c *servicep;

for (servicep = self->services; servicep != NULL; servicep = servicep->next) {
  usbServiceOnWakeupI(servicep);
}

hal_usb_service_c *servicep;

for (servicep = self->services; servicep != NULL; servicep = servicep->next) {
  usbServiceOnSOFI(servicep);
}

hal_usb_service_c *servicep;

for (servicep = self->services; servicep != NULL; servicep = servicep->next) {
  if (usbServiceOwnsInEndpointX(servicep, ep)) {
    usbServiceOnInI(servicep, ep);
    return;
  }
}

hal_usb_service_c *servicep;

for (servicep = self->services; servicep != NULL; servicep = servicep->next) {
  if (usbServiceOwnsOutEndpointX(servicep, ep)) {
    usbServiceOnOutI(servicep, ep);
    return;
  }
}

hal_usb_service_c *servicep;

*handledp = false;
for (servicep = self->services; servicep != NULL; servicep = servicep->next) {
  msg_t msg;
  bool handled;

  handled = false;
  msg = usbServiceSetup(servicep, &handled);
  if ((msg != HAL_RET_SUCCESS) || handled) {
    *handledp = handled;
    return msg;
  }
}

return HAL_RET_SUCCESS;

