abase  = (unsigned)ap->if_base;
alimit = abase + (unsigned)ap->if_count;
bbase  = (unsigned)bp->if_base;
blimit = bbase + (unsigned)bp->if_count;

return (abase < blimit) && (bbase < alimit);

